const body = $input.first().json.body;

const city = body.city;
const country = body.country;
const venue = body.venue;
const match = body.match;
const estValue = body.estValue || '';
const flightEstimate = body.flightEstimate || '';
const courses = (body.selectedCourses || []).join(' and ');
const weather = body.weather;

let weatherLine = '';
if (weather) {
  weatherLine = `Current conditions in ${city}: ${weather.temperature}°C, ${weather.condition}. ` +
    `Today's high ${weather.high}°C, low ${weather.low}°C. ` +
    `Wind ${weather.windspeed} km/h. Rain chance ${weather.rainChance}%.`;
}

const prompt = `You are a luxury golf travel writer for Golf Travel Group (GTG), crafting bespoke World Cup 2026 trip itineraries for high-net-worth clients.

Trip details:
- Destination: ${city}, ${country}
- World Cup fixture: ${match}
- Stadium: ${venue}
- Golf courses selected: ${courses}
${estValue ? `- Estimated trip value: ${estValue} per person` : ''}
${flightEstimate ? `- Flights from UK: ${flightEstimate} return economy` : ''}
${weatherLine ? `\nWeather context:\n${weatherLine}` : ''}

Write a 3-day luxury golf itinerary in the following EXACT JSON format. Do not include any text outside the JSON.

JSON format:
{
  "city": "${city}",
  "country": "${country}",
  "match": "${match}",
  "venue": "${venue}",
  "estValue": "${estValue}",
  "days": [
    { "title": "Day 1 title", "text": "Day 1 description (2-3 sentences, warm and specific, mention the course by name and include a weather detail if relevant)" },
    { "title": "Day 2 title", "text": "Day 2 description — this is match day, centre the experience on the fixture at ${venue}" },
    { "title": "Day 3 title", "text": "Day 3 description — farewell round, a relaxed close to the trip" }
  ]
}

Tone: editorial luxury travel, warm but precise. Never say 'vibrant' or 'world-class'. Write as if the client is already on the trip.`;

return [{ json: { prompt } }];

const raw = $input.first().json.choices?.[0]?.message?.content || $input.first().json.text || '';

let parsed;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
} catch (e) {
  parsed = null;
}

if (!parsed) {
  return [{ json: { error: true, message: 'Could not parse Groq response', raw } }];
}

return [{ json: parsed }];
